SELECT COUNT(trade_id) AS total_trades
FROM trade_records
WHERE strategy_id = 1;

SELECT strategy_id, COUNT(*) AS total_trades
FROM trade_records
GROUP BY strategy_id;

SELECT DISTINCT year, strategy_id
FROM performance_metrics
ORDER BY year, strategy_id;

SELECT strategy_name
FROM investment_strategies
WHERE strategy_id = 1;

SELECT strategy_name 
FROM investment_strategies 
ORDER BY strategy_name;

SELECT COUNT(strategy_id) AS strategy_count
FROM investment_strategies
WHERE created_by = 1;
